export const meta = {
  name: 'explore-opencore-codebase',
  description: '联合深度探索 OpenCoreSDK 代码库 + 横向对比调研',
  phases: [
    { title: '扫描' },
    { title: '架构分析' },
    { title: '领域分析' },
    { title: '文件分析' },
    { title: '学习路径' },
    { title: '图谱审查' }
  ],
}

const PROJECT_PATH = '/home/cwtrocks/OpenCoreSDK'

phase('扫描')
const scanResult = await agent(
  `扫描项目 ${PROJECT_PATH}，识别语言、构建系统、依赖、文件结构`,
  { agentType: 'understand-anything:project-scanner', phase: '扫描' }
)

phase('架构分析')
const archResult = await agent(
  `分析 ${PROJECT_PATH} 的架构层次和模块依赖，识别设计模式`,
  { agentType: 'understand-anything:architecture-analyzer', phase: '架构分析' }
)

phase('领域分析')
const domainResult = await agent(
  `提取 ${PROJECT_PATH} 的业务领域和核心概念，分析领域模型`,
  { agentType: 'understand-anything:domain-analyzer', phase: '领域分析' }
)

phase('文件分析')
const fileAnalyses = await pipeline(
  ['coredump.cpp', 'crash_handler.cpp', 'elf_writer.cpp'],
  async (file) => await agent(
    `深度分析 ${PROJECT_PATH}/src/${file}，提取类、函数、算法和关键数据结构`,
    { phase: '文件分析' }
  )
)

phase('学习路径')
const tourResult = await agent(
  `基于分析结果，生成 ${PROJECT_PATH} 的 5-15 步结构化学习路径`,
  { agentType: 'understand-anything:tour-builder', phase: '学习路径' }
)

phase('图谱审查')
const reviewResult = await agent(
  `审查验证 ${PROJECT_PATH} 的知识图谱，检查完整性和一致性`,
  { agentType: 'understand-anything:graph-reviewer', phase: '图谱审查' }
)

return { scanResult, archResult, domainResult, fileAnalyses, tourResult, reviewResult }
